//-------------------------------------------------------------------------
// 저장버튼 처리 
//-------------------------------------------------------------------------
scwin.isGrdDupDataFlag = async function (grdObj, strGrdNm, colObj) {
  var sRtn = false;
  let hVal = "",
    tHval = "";
  let dataListObj = $p.getComponentById(grdObj.getDataList());

  // alert 출력을 위해서 헤더 정보값을 만든다
  for (let idx in colObj) {
    hVal = grdObj.getHeaderValue(grdObj.getHeaderID(grdObj.getColumnIndex(colObj[idx]))) || "이름없음";
    hVal = hVal.replace(/<[^>]*>/gi, "").replace(" ", "");
    if (tHval.length == 0) {
      tHval = hVal;
    } else {
      tHval = tHval + ", " + hVal;
    }
  }

  // 배열에 컬럼값들 합쳐서 담기.
  let colData, rowData;
  let colChkAllData = [];
  for (var i = 0; i < dataListObj.getRowCount(); i++) {
    rowData = "";
    for (let idx in colObj) {
      colData = dataListObj.getCellData(i, colObj[idx]);
      if (idx == 0) {
        rowData = colData;
      } else {
        rowData = rowData + colData;
      }
    }
    colChkAllData.push(rowData);
  }

  // 데이터 중복 체크
  const result = {};
  let dupIdx;
  sRtn = colChkAllData.some((value, key) => {
    result[value] = (result[value] || 0) + 1;
    if (result[value] > 1) {
      dupIdx = key + 1;
      return true;
    }
  });
  if (sRtn && dupIdx != undefined && dupIdx != null && dupIdx != "") {
    await $c.win.alert($p, strGrdNm + "의 " + dupIdx + "번째 데이터에서 " + tHval + "은(는) 중복될 수 없습니다.");
    scwin.sleep(50).then(function () {
      /*
      if(gr_oilUnitPrice.getFocusedColumnID() != undefined && gr_oilUnitPrice.getFocusedColumnID() != null && gr_oilUnitPrice.getFocusedColumnID() != "") {
          grdObj.setFocusedCell(dupIdx-1, gr_oilUnitPrice.getFocusedColumnID());
      } else {
          grdObj.setFocusedCell(dupIdx-1, colObj[colObj.length-1]);
      }
      */
      grdObj.setFocusedCell(dupIdx - 1, colObj[colObj.length - 1]), true;
    });
  }
  return sRtn;
};
scwin.f_Save = async function () {
  if (ds_RailroadWorkPlan.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_049, ["변경사항"]);
    return;
  }
  for (var i = 0; i < ds_RailroadWorkPlan.getRowCount(); i++) {
    if (ds_RailroadWorkPlan.getRowStatus(i) == "C" || ds_RailroadWorkPlan.getRowStatus(i) == "U") {
      if (ds_RailroadWorkPlan.getCellData(i, "cntrNo") == "") {
        await $c.gus.cfAlertMsg($p, "[" + (i + 1) + "번째 줄]" + MSG_CM_ERR_002, ["컨테이너번호"]);
        gr_RailroadWorkPlan.setFocusedCell(i, "cntrNo");
        return false;
      }
      if (ds_RailroadWorkPlan.getCellData(i, "dptStnWrkPlNm") == "") {
        await $c.gus.cfAlertMsg($p, "[" + (i + 1) + "번째 줄]" + MSG_CM_ERR_002, ["출발역"]);
        gr_RailroadWorkPlan.setFocusedCell(i, "dptStnWrkPlNm");
        return false;
      }
      if (ds_RailroadWorkPlan.getCellData(i, "odrNo") == "") {
        await $c.gus.cfAlertMsg($p, "[" + (i + 1) + "번째 줄]" + MSG_CM_ERR_002, ["오더번호"]);
        gr_RailroadWorkPlan.setFocusedCell(i, "odrNo");
        return false;
      }
      if (ds_RailroadWorkPlan.getCellData(i, "frtcarNo") == "") {
        await $c.gus.cfAlertMsg($p, "[" + (i + 1) + "번째 줄]" + MSG_CM_ERR_002, ["화차번호"]);
        gr_RailroadWorkPlan.setFocusedCell(i, "frtcarNo");
        return false;
      }
      if (ds_RailroadWorkPlan.getCellData(i, "clntNm") == "") {
        await $c.gus.cfAlertMsg($p, "[" + (i + 1) + "번째 줄]" + MSG_CM_ERR_002, ["화주명"]);
        gr_RailroadWorkPlan.setFocusedCell(i, "clntNm");
        return false;
      }
      if (ds_RailroadWorkPlan.getCellData(i, "vsslNm") == "") {
        await $c.gus.cfAlertMsg($p, "[" + (i + 1) + "번째 줄]" + MSG_CM_ERR_002, ["모선명"]);
        gr_RailroadWorkPlan.setFocusedCell(i, "vsslNm");
        return false;
      }
    }
  }
  let ret = await $c.gus.cfValidate($p, [gr_RailroadWorkPlan]);
  if (!ret) {
    return false;
  }
  ret = await scwin.isGrdDupDataFlag(gr_RailroadWorkPlan, "철송내역", ["dptStnWrkPlNm", "cntrNo", "odrNo"]);
  if (ret) {
    return false;
  }
  let confirmResult = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (confirmResult) {
    //tr_SaveRailroadWorkPlan.Post();
    //submit 처리.
    let objSubmit = await $c.sbm.execute($p, sbm_SaveRailroadWorkPlan);
    if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
      await scwin.sbm_SaveRailroadWorkPlan_submitdone();
    }
    scwin.order_chk = "N";
  }
};
scwin.sbm_SaveRailroadWorkPlan_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  await $c.gus.cfAlertMsg($p, MSG_CM_INF_001);
  scwin.f_qeryList();
};

