scwin.f_inputGridAddrow = function () {
  if (scwin.initOnloadFlag) {
    return;
  }
  var nRow = ds_RailroadWorkPlan.getRowCount();
  ds_RailroadWorkPlan.insertRow(nRow);
  ds_RailroadWorkPlan.setCellData(nRow, "reqDt", scwin.dateStr1);
  ds_RailroadWorkPlan.setCellData(nRow, "dptStnWrkPlCd", ed_begintrainWorkPlaceCd.getValue());
  ds_RailroadWorkPlan.setCellData(nRow, "dptStnWrkPlNm", ed_begintrainWorkPlaceNm.getValue());
  ds_RailroadWorkPlan.setCellData(nRow, "adminfrtcarYn", '3');

  //발송여부
  ds_RailroadWorkPlan.setCellData(nRow, "dptArvYn", '0');
  //중량
  ds_RailroadWorkPlan.setCellData(nRow, "wt", 0);
  if (ed_endtrainWorkPlaceCd.getValue() != "") {
    ds_RailroadWorkPlan.setCellData(nRow, "arvStnWrkPlCd", ed_endtrainWorkPlaceCd.getValue());
    ds_RailroadWorkPlan.setCellData(nRow, "arvStnWrkPlNm", ed_endtrainWorkPlaceNm.getValue());
  }
  ds_RailroadWorkPlan.setRowPosition(nRow);
};

//행삭제 버튼 클릭시
scwin.f_rowDel = function () {
  if (scwin.initOnloadFlag) {
    return;
  }

  //그리드에 매핑된 dataList의 row가 신규행이면 삭제하고 아니면 삭제마크처리.
  if (ds_RailroadWorkPlan.getRowStatus(ds_RailroadWorkPlan.getRowPosition()) == "C") {
    ds_RailroadWorkPlan.removeRow(ds_RailroadWorkPlan.getRowPosition());
  } else {
    ds_RailroadWorkPlan.deleteRow(ds_RailroadWorkPlan.getRowPosition());
  }
};

//취소 버튼 클릭시
scwin.f_cancel = function () {
  if (scwin.initOnloadFlag) {
    return;
  }

  //그리드에 매핑된 dataList rowIdx 미존재시 이전에 클릭했던 rowIdx 셋팅처리.
  if (ds_RailroadWorkPlan.getRowPosition() == null) {
    ds_RailroadWorkPlan.setRowPosition(scwin.gridRowIdx);
  }
  $c.data.undoRow($p, ds_RailroadWorkPlan, "Y");
};

//그리드에 매핑된 dataList rowStatus 가 변경시.
scwin.ds_RailroadWorkPlan_onrowstatuschange = function (info) {
  //해당 ROW 수정 후 삭제처리시
  if (info[0].oldRowStatus == "U") {
    if (info[0].newRowStatus == "D") {
      $c.data.undoRow($p, ds_RailroadWorkPlan, "Y");
      ds_RailroadWorkPlan.deleteRow(info[0].rowIndex);
    }
  }
};

