scwin.udc_AllInOne_callBackFunc = function (rtnList) {
  let codeObj;
  let nameObj;
  var sRtnFlag = true;

  //출발역(comp)
  if (scwin.udc_objNm == "udc_begintrainWorkPlace") {
    codeObj = ed_begintrainWorkPlaceCd;
    nameObj = ed_begintrainWorkPlaceNm;

    //도착지코드          도착지명
    $c.gus.cfSetReturnValue($p, rtnList, codeObj, nameObj);
    if (rtnList != null) {
      scwin.edisndYn = rtnList[2];
    }
  }
  //도착역(comp)
  else if (scwin.udc_objNm == "udc_endtrainWorkPlace") {
    codeObj = ed_endtrainWorkPlaceCd;
    nameObj = ed_endtrainWorkPlaceNm;

    //도착지코드          도착지명
    $c.gus.cfSetReturnValue($p, rtnList, codeObj, nameObj);
  }
  //출발역(grid)
  else if (scwin.udc_objNm == "udc_grid_dptStnWrkPlNm") {
    if (rtnList != null && rtnList[0] != 'N/A') {
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "dptStnWrkPlCd", rtnList[0]); //작업장코드
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "dptStnWrkPlNm", rtnList[1]); //작업장명
      if (ds_RailroadWorkPlan.getCellData(ds_RailroadWorkPlan.getRowPosition(), "dptStnWrkPlNm") == 'undefined') {
        ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "dptStnWrkPlNm", '');
      }
    }
  }
  //도착역(grid)
  else if (scwin.udc_objNm == "udc_grid_arvStnWrkPlNm") {
    if (rtnList != null && rtnList[0] != 'N/A') {
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "arvStnWrkPlCd", rtnList[0]); //작업장코드
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "arvStnWrkPlNm", rtnList[1]); //작업장명
      if (ds_RailroadWorkPlan.getCellData(ds_RailroadWorkPlan.getRowPosition(), "arvStnWrkPlNm") == 'undefined') {
        ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "arvStnWrkPlNm", '');
      }
    }
  }
  //등록자(comp)
  else if (scwin.udc_objNm == "udc_alloccarPic") {
    codeObj = em_alloccarPicId;
    nameObj = ed_alloccarPicNm;
    $c.gus.cfSetReturnValue($p, rtnList, codeObj, nameObj);
  }
  //화주명(grid)
  else if (scwin.udc_objNm == "udc_grid_clntNm") {
    if (rtnList != null && rtnList[0] != 'N/A') {
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "clntNo", rtnList[0]); //작업장코드
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "clntNm", rtnList[1]); //작업장명
      if (ds_RailroadWorkPlan.getCellData(ds_RailroadWorkPlan.getRowPosition(), "clntNm") == 'undefined') {
        ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "clntNm", '');
      }
    }
  }
  //포트(grid)
  else if (scwin.udc_objNm == "udc_grid_portCd") {
    if (rtnList != null && rtnList[0] != 'N/A') {
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "portCd", rtnList[0]); //작업장코드
    }
  }
  //모선명(grid)
  else if (scwin.udc_objNm == "udc_grid_vsslNm") {
    if (rtnList != null && rtnList[0] != 'N/A') {
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "vsslCd", rtnList[0]); //작업장코드
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "vsslNm", rtnList[1]); //작업장명
      if (ds_RailroadWorkPlan.getCellData(ds_RailroadWorkPlan.getRowPosition(), "vsslNm") == 'undefined') {
        ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "vsslNm", '');
      }
    }
  }
  //하차지(grid)
  else if (scwin.udc_objNm == "udc_grid_arvWrkPlNm") {
    if (rtnList != null && rtnList[0] != 'N/A') {
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "arvWrkPlCd", rtnList[0]); //작업장코드
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "arvWrkPlNm", rtnList[1]); //작업장명
      if (ds_RailroadWorkPlan.getCellData(ds_RailroadWorkPlan.getRowPosition(), "arvWrkPlNm") == 'undefined') {
        ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "arvWrkPlNm", '');
      }
    } else {
      ds_RailroadWorkPlan.setCellData(ds_RailroadWorkPlan.getRowPosition(), "arvWrkPlNm", '');
    }
  }
  //청구처(comp)
  else if (scwin.udc_objNm == "udc_bilgClnt") {
    codeObj = ed_bilgClntNo;
    nameObj = ed_bilgClntNm;
    $c.gus.cfSetReturnValue($p, rtnList, codeObj, nameObj); // 청구거래처코드, 청구거래처명
  }
  //라인(comp)
  else if (scwin.udc_objNm == "udc_line") {
    codeObj = ed_lineCd;
    nameObj = ed_lineNm;
    $c.gus.cfSetReturnValue($p, rtnList, codeObj, nameObj); // LINE코드, LINE명
  }
  return sRtnFlag;
};

