scwin.ds_RailroadWorkPlan_col_length_check = async function (sourceObj, targetObj, colNm, nRow) {
  var nChkLen = Number(targetObj.getCellData(0, colNm));
  var sData = sourceObj.getCellData(nRow, colNm);
  var nDataLen = $p.getStringByteSize(sData.toString());
  if (nDataLen > nChkLen) {
    var chgData = sData.toString().substring(0, nChkLen);
    sourceObj.setCellData(nRow, colNm, chgData);
  }
};

//화차번호 업로드처리.
scwin.f_Upload2 = async function () {
  ds_FrtcarNoUpload.removeAll();
  await scwin.f_qeryList();
  if (ds_RailroadWorkPlan.getRowCount() <= 0) {
    return;
  }
  var options = {
    //startRowIndex: 2,
    type: 1
  };
  switch (rd_upload.getValue()) {
    // xlsx
    case '0':
      await $c.data.uploadGridViewExcel($p, gr_FrtcarNoUpload, options);
      break;
    // csv
    case '1':
      await $c.data.uploadGridViewCSV($p, gr_FrtcarNoUpload, options);
      break;
  }
};
scwin.gr_FrtcarNoUpload_onfilereadend = function (value) {
  for (var i_frtcarNo = 0; i_frtcarNo < ds_FrtcarNoUpload.getRowCount(); i_frtcarNo++) {
    if (ds_FrtcarNoUpload.getCellData(i_frtcarNo, "frtcarNo") != "0" && ds_FrtcarNoUpload.getCellData(i_frtcarNo, "frtcarNo") != "") {
      for (var i_cntrNo = 0; i_cntrNo < ds_RailroadWorkPlan.getRowCount(); i_cntrNo++) {
        if (ds_FrtcarNoUpload.getCellData(i_frtcarNo, "cntrNo") == ds_RailroadWorkPlan.getCellData(i_cntrNo, "cntrNo")) {
          ds_RailroadWorkPlan.setCellData(i_cntrNo, "frtcarNo", ds_FrtcarNoUpload.getCellData(i_frtcarNo, "frtcarNo"));
          break;
        }
      }
    }
  }
};

